import{_ as e,o as t,c as i,aJ as l}from"./chunks/framework.DaXVObk1.js";const p=JSON.parse('{"title":"Canvas 学习大纲与面试指南","description":"","frontmatter":{},"headers":[],"relativePath":"Canvas/canvas.md","filePath":"Canvas/canvas.md"}'),s={name:"Canvas/canvas.md"};function n(o,a,r,d,g,c){return t(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="canvas-学习大纲与面试指南" tabindex="-1">Canvas 学习大纲与面试指南 <a class="header-anchor" href="#canvas-学习大纲与面试指南" aria-label="Permalink to “Canvas 学习大纲与面试指南”">​</a></h1><h2 id="_1-基础认知" tabindex="-1">1. 基础认知 <a class="header-anchor" href="#_1-基础认知" aria-label="Permalink to “1. 基础认知”">​</a></h2><h3 id="_1-1-canvas-是什么" tabindex="-1">1.1 Canvas 是什么 <a class="header-anchor" href="#_1-1-canvas-是什么" aria-label="Permalink to “1.1 Canvas 是什么”">​</a></h3><p>Canvas 是 HTML5 新增的元素，用于通过 JavaScript 脚本来绘制图形。默认大小 300x150。它提供了一个<strong>即时模式（Immediate Mode）</strong>的图形系统 - 意味着一旦绘制完成，浏览器就会忘记该图形，所有后续修改都需要重绘。</p><h3 id="_1-2-canvas-vs-svg-面试高频" tabindex="-1">1.2 Canvas vs SVG (面试高频) <a class="header-anchor" href="#_1-2-canvas-vs-svg-面试高频" aria-label="Permalink to “1.2 Canvas vs SVG (面试高频)”">​</a></h3><p>这是面试中最常问的图形学对比题。</p><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">Canvas</th><th style="text-align:left;">SVG</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>本质</strong></td><td style="text-align:left;"><strong>位图</strong> (基于像素)</td><td style="text-align:left;"><strong>矢量图</strong> (基于形状)</td></tr><tr><td style="text-align:left;"><strong>模式</strong></td><td style="text-align:left;">即时模式 (无状态)</td><td style="text-align:left;">保留模式 (DOM 节点)</td></tr><tr><td style="text-align:left;"><strong>事件处理器</strong></td><td style="text-align:left;">不支持 (只能监听整个 canvas 元素的事件)</td><td style="text-align:left;">支持 (每个 SVG 元素都是 DOM，可直接绑定事件)</td></tr><tr><td style="text-align:left;"><strong>性能瓶颈</strong></td><td style="text-align:left;">受<strong>分辨率</strong>影响大 (像素越多越慢)</td><td style="text-align:left;">受<strong>对象数量</strong>影响大 (DOM 越多越慢)</td></tr><tr><td style="text-align:left;"><strong>适用场景</strong></td><td style="text-align:left;">游戏、大量数据可视化(如热力图)、图像处理、粒子效果</td><td style="text-align:left;">图标、地图(交互强)、高保真文档、常规图表</td></tr><tr><td style="text-align:left;"><strong>缩放</strong></td><td style="text-align:left;">放大后失真 (像素化)</td><td style="text-align:left;">放大后不失真</td></tr></tbody></table><h2 id="_2-核心绘制-api" tabindex="-1">2. 核心绘制 API <a class="header-anchor" href="#_2-核心绘制-api" aria-label="Permalink to “2. 核心绘制 API”">​</a></h2><h3 id="_2-1-路径-path-系统" tabindex="-1">2.1 路径 (Path) 系统 <a class="header-anchor" href="#_2-1-路径-path-系统" aria-label="Permalink to “2.1 路径 (Path) 系统”">​</a></h3><p>Canvas 的绘图核心是路径。</p><ul><li><code>beginPath()</code>: 开始一条新路径（清空之前的路径列表）。</li><li><code>closePath()</code>: 闭合路径（将终点与起点连接）。</li><li><code>moveTo(x, y)</code>: 移动画笔。</li><li><code>lineTo(x, y)</code>: 绘制直线。</li><li><code>arc(x, y, r, startAngle, endAngle)</code>: 绘制圆弧。</li><li><code>stroke()</code> / <code>fill()</code>: 真正的绘制指令。</li></ul><h3 id="_2-2-图片操作-drawimage-重点" tabindex="-1">2.2 图片操作 <code>drawImage</code> (重点) <a class="header-anchor" href="#_2-2-图片操作-drawimage-重点" aria-label="Permalink to “2.2 图片操作 drawImage (重点)”">​</a></h3><p><code>ctx.drawImage()</code> 是 Canvas 中最通用的搬运工，它可以将<strong>图像源</strong>绘制到画布上。 <strong>支持的数据源</strong>：<code>HTMLImageElement</code> (img标签/new Image), <code>HTMLVideoElement</code> (视频帧), <code>HTMLCanvasElement</code> (另一个canvas), <code>ImageBitmap</code>。</p><p>该方法有三种使用模式，参数数量不同，功能也从简单到复杂：</p><h4 id="_1-基础定位绘制-3参数" tabindex="-1">1. 基础定位绘制 (3参数) <a class="header-anchor" href="#_1-基础定位绘制-3参数" aria-label="Permalink to “1. 基础定位绘制 (3参数)”">​</a></h4><p><code>ctx.drawImage(image, dx, dy)</code></p><ul><li><strong>做了啥</strong>：把<strong>整张图</strong>原封不动地画在画布的 <code>(dx, dy)</code> 坐标处。</li><li><strong>大小</strong>：图片保持原始自然宽度和高度。</li><li><strong>场景</strong>：简单的贴图、背景图绘制。</li></ul><h4 id="_2-缩放绘制-5参数" tabindex="-1">2. 缩放绘制 (5参数) <a class="header-anchor" href="#_2-缩放绘制-5参数" aria-label="Permalink to “2. 缩放绘制 (5参数)”">​</a></h4><p><code>ctx.drawImage(image, dx, dy, dWidth, dHeight)</code></p><ul><li><strong>做了啥</strong>：把<strong>整张图</strong>画在画布上，但是强制拉伸/压缩到指定的大小 <code>dWidth</code> x <code>dHeight</code>。</li><li><strong>大小</strong>：图片会变形以适应你指定的宽。</li><li><strong>场景</strong>：生成缩略图、背景填充满画布、简单的图片尺寸调整。</li></ul><h4 id="_3-切片-剪裁绘制-9参数-面试与实战核心" tabindex="-1">3. 切片/剪裁绘制 (9参数) - 面试与实战核心 <a class="header-anchor" href="#_3-切片-剪裁绘制-9参数-面试与实战核心" aria-label="Permalink to “3. 切片/剪裁绘制 (9参数) - 面试与实战核心”">​</a></h4><p><code>ctx.drawImage(image, sx, sy, sWidth, sHeight, dx, dy, dWidth, dHeight)</code> 这是最强大但也最容易晕的模式。</p><ul><li><strong>记忆口诀</strong>：<strong>&quot;先看原图剪哪里(Source)，再看画布画哪里(Destination)&quot;</strong>。</li><li><strong>参数详解</strong>： <ul><li><code>sx, sy</code>: <strong>源图起点</strong>。从原图片的哪个坐标开始切。</li><li><code>sWidth, sHeight</code>: <strong>源图尺寸</strong>。在原图上切多大的一块区域。</li><li><code>dx, dy</code>: <strong>画布起点</strong>。切下来的这块，放在画布的哪里。</li><li><code>dWidth, dHeight</code>: <strong>画布尺寸</strong>。切下来的这块，在画布上要显示多大（支持缩放）。</li></ul></li><li><strong>做了啥</strong>：它像这把剪刀，先从原图剪下一块矩形，然后像贴纸一样贴（可能还会拉伸）到画布指定位置。</li><li><strong>场景</strong>： <ul><li><strong>雪碧图 (Sprite)</strong>：游戏中常见，一张大图里塞满了角色的跑、跳、攻击动作。通过改变 <code>sx, sy</code> 就可以让角色动起来。</li><li><strong>局部放大镜</strong>：截取图片一小块，画到一个大区域里。</li></ul></li></ul><h4 id="⚠️-实战中的坑与面试点" tabindex="-1">⚠️ 实战中的坑与面试点： <a class="header-anchor" href="#⚠️-实战中的坑与面试点" aria-label="Permalink to “⚠️ 实战中的坑与面试点：”">​</a></h4><ol><li><p><strong>异步加载问题 (必考)</strong>：</p><ul><li><code>drawImage</code> 是同步的，但图片加载是异步的。如果不等图片加载完直接画，画布是白色的且不报错。</li><li><strong>正确写法</strong>：<div class="language-javascript"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> img</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> new</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">img.src </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;hero.png&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 一定要在 onload 回调里画！</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">img.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">onload</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> () </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ctx.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">drawImage</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(img, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre></div></li></ul></li><li><p><strong>图片跨域 (Tainted Canvas)</strong>:</p><ul><li>如果绘制的图片来自不同域且未开启 CORS，调用 <code>toDataURL</code> 或 <code>getImageData</code> 会报错 <code>SecurityError</code>。</li><li><em>解法</em>：服务端设置 CORS头，前端 img 设置 <code>crossOrigin = &#39;anonymous&#39;</code>。</li></ul></li><li><p><strong>性能细节</strong>：</p><ul><li>在动画循环里 <code>new Image()</code> 是大忌。应该在外面创建好 img 对象，循环里只调 drawImage。</li></ul></li></ol><h3 id="_2-3-像素级操作-imagedata" tabindex="-1">2.3 像素级操作 (ImageData) <a class="header-anchor" href="#_2-3-像素级操作-imagedata" aria-label="Permalink to “2.3 像素级操作 (ImageData)”">​</a></h3><ul><li><strong>API</strong>: <code>getImageData(x, y, w, h)</code>, <code>putImageData(imageData, x, y)</code>.</li><li><strong>数据结构</strong>: 返回的 <code>data</code> 是一个 <code>Uint8ClampedArray</code>，每4个位置代表一个像素 (R, G, B, A)。</li><li><strong>应用</strong>: 滤镜(灰度、反色)、拾色器、绿幕抠图。</li><li><strong>性能</strong>: <code>getImageData</code> 非常消耗性能（通常会导致 GPU 到 CPU 的数据回读），动画循环中应避免频繁调用。</li></ul><h2 id="_3-变换与状态管理" tabindex="-1">3. 变换与状态管理 <a class="header-anchor" href="#_3-变换与状态管理" aria-label="Permalink to “3. 变换与状态管理”">​</a></h2><h3 id="_3-1-状态栈-save-restore" tabindex="-1">3.1 状态栈 (<code>save</code> / <code>restore</code>) <a class="header-anchor" href="#_3-1-状态栈-save-restore" aria-label="Permalink to “3.1 状态栈 (save / restore)”">​</a></h3><p>Canvas 的状态（State）包括：当前的颜色、线宽、变换矩阵、裁剪区域等。</p><ul><li><code>ctx.save()</code>: 将当前状态推入栈中。</li><li><code>ctx.restore()</code>: 弹出栈顶状态。</li></ul><p><strong>面试考点</strong>：为什么要用 save/restore？</p><ul><li>答：在进行 <code>translate</code>/<code>rotate</code> 等变换或修改全局样式（如 <code>globalAlpha</code>）前保存状态，绘制结束后恢复，防止污染后续图形的绘制环境。</li></ul><h3 id="_3-2-坐标变换" tabindex="-1">3.2 坐标变换 <a class="header-anchor" href="#_3-2-坐标变换" aria-label="Permalink to “3.2 坐标变换”">​</a></h3><ul><li><code>translate(x, y)</code>: 移动原点。</li><li><code>rotate(angle)</code>: 旋转坐标系 (注意是绕原点旋转，通常需配合 translate 实现中心旋转)。</li><li><code>scale(x, y)</code>: 缩放。</li></ul><h2 id="_4-交互与动画" tabindex="-1">4. 交互与动画 <a class="header-anchor" href="#_4-交互与动画" aria-label="Permalink to “4. 交互与动画”">​</a></h2><h3 id="_4-1-动画循环" tabindex="-1">4.1 动画循环 <a class="header-anchor" href="#_4-1-动画循环" aria-label="Permalink to “4.1 动画循环”">​</a></h3><ul><li><strong>推荐</strong>: <code>window.requestAnimationFrame(callback)</code>。</li><li><strong>流程</strong>: 清除 (<code>clearRect</code>) -&gt; 更新状态 -&gt; 绘制 -&gt; 请求下一帧。</li></ul><h3 id="_4-2-交互事件-难点" tabindex="-1">4.2 交互事件 (难点) <a class="header-anchor" href="#_4-2-交互事件-难点" aria-label="Permalink to “4.2 交互事件 (难点)”">​</a></h3><p><strong>问题</strong>: Canvas 里的画了一个圆，怎么知道用户点击了这个圆？</p><ol><li><strong>几何计算法</strong>: 算出鼠标点到圆心的距离是否小于半径。适合简单图形。</li><li><strong>API 判断法</strong>: <code>ctx.isPointInPath(x, y)</code>。判断点是否在当前构建的路径内。</li><li><strong>颜色索引法 (Color Picking)</strong>: <ul><li>在离屏 Canvas 上用不同颜色绘制每个图形（颜色值对应图形 ID）。</li><li>用户点击时，在离屏 Canvas 对应坐标获取像素颜色 <code>getImageData</code>。</li><li>根据颜色解析出 ID。适合复杂且数量非常多的图形。</li></ul></li></ol><h2 id="_5-性能优化-进阶必问" tabindex="-1">5. 性能优化 (进阶必问) <a class="header-anchor" href="#_5-性能优化-进阶必问" aria-label="Permalink to “5. 性能优化 (进阶必问)”">​</a></h2><ol><li><strong>离屏渲染 (Offscreen Rendering)</strong>: <ul><li>创建一个内存中的 canvas (<code>document.createElement(&#39;canvas&#39;)</code>) 预先绘制好复杂的静态图形。</li><li>主画布渲染时直接 <code>drawImage</code> 这个离屏 canvas。</li></ul></li><li><strong>分层渲染 (Layering)</strong>: <ul><li>背景层（静态）用一个 <code>&lt;canvas&gt;</code>，前景层（动画）用另一个 <code>&lt;canvas&gt;</code> 覆盖在上面。避免背景频繁重绘。</li></ul></li><li><strong>避免浮点数坐标</strong>: <ul><li>使用 <code>Math.floor()</code> 取整。浮点数会导致抗锯齿运算，增加 GPU 负担且可能让线条模糊。</li></ul></li><li><strong>视口裁剪 (Culling)</strong>: <ul><li>只绘制在屏幕可视范围内的图形。</li></ul></li><li><strong>减少 API 调用</strong>: <ul><li>比如画 1000 条同色直线，应该 <code>beginPath</code> -&gt; 循环 <code>moveTo/lineTo</code> -&gt; 最后一次性 <code>stroke</code>，而不是循环 <code>stroke</code>。</li></ul></li></ol><h2 id="_6-一些特定的面试题积累" tabindex="-1">6. 一些特定的面试题积累 <a class="header-anchor" href="#_6-一些特定的面试题积累" aria-label="Permalink to “6. 一些特定的面试题积累”">​</a></h2><ol><li><p><strong>如何解决 Canvas 在高清屏 (Retina) 下模糊的问题？</strong></p><ul><li><em>原理</em>：<code>devicePixelRatio</code> (DPR)。</li><li><em>解法</em>：将 canvas 的 <code>width/height</code> (画布分辨率) 设置为 <code>CSS 宽高 * DPR</code>，然后通过 <code>scale(DPR, DPR)</code> 缩放上下文，或者 CSS 强行指定显示大小。</li></ul></li><li><p><strong>Canvas 如何实现撤销/重做 (Undo/Redo)？</strong></p><ul><li><em>快照法</em>：用 <code>getImageData</code> 保存每一步的历史记录（内存占用大）。</li><li><em>命令模式</em>：记录每一步的绘图指令（数据+操作），重做时清空画布重新执行指令数组（性能好，适合长时间操作）。</li></ul></li><li><p><strong>常见前端应用</strong></p><ul><li><strong>ECharts/AntV</strong>: 底层渲染引擎 (ZRender)。</li><li><strong>html2canvas</strong>: DOM 转图片截图。</li><li><strong>图片压缩</strong>: <code>canvas.toDataURL(&#39;image/jpeg&#39;, 0.5)</code>。</li><li><strong>签名板</strong>: 记录鼠标轨迹并绘制。</li></ul></li></ol>`,45)])])}const k=e(s,[["render",n]]);export{p as __pageData,k as default};
